sql:
SELECT protein_id 
FROM proteins 
ORDER BY protein_id;

SELECT protein_name, species
FROM proteins
ORDER BY species, protein_name;

SELECT protein_name
FROM proteins
ORDER BY protein_name;

external_knowledge:
- The term "top-ranked proteins" refers to proteins with the highest confidence scores; 
- Confidence scores measure the reliability of the protein's localization pattern; 
- A confidence score greater than 0.9 indicates high confidence in the localization of a protein.
